# Binary Tree in Java

Here's a complete implementation of a binary tree data structure in Java:

```java
public class BinaryTree

    // Node class to represent each tree node
    static class TreeNode
        int data;
        TreeNode left;
        TreeNode right;

        public TreeNode(int value)
            this.data = value;
            this.left = null;
            this.right = null;
        }
    }

    // Root of the binary tree
    private TreeNode root;

    // Constructor
    public BinaryTree()
        this.root = null;
    }

    // Insert a new node (add as left child if not exists)
    public void insert(int value)
        if (root == null)
            root = new TreeNode(value);
            return;
        }

        TreeNode current = root;
        while (true)
            if (value < current.data)
                if (current.left == null)
                    current.left = new TreeNode(value);
                    break;
                }
                current = current.left;
            } else
                if (current.right == null)
                    current.right = new TreeNode(value);
                    break;
                }
                current = current.right;
            }
        }
    }

    // In-order traversal (Left, Root, Right) - returns sorted order
    public void inOrderTraversal(TreeNode node)
        if (node != null)
            inOrderTraversal(node.left);
            System.out.print(node.data + " ");
            inOrderTraversal(node.right);
        }
    }

    // Pre-order traversal (Root, Left, Right)
    public void preOrderTraversal(TreeNode node)
        if (node != null)
            System.out.print(node.data + " ");
            preOrderTraversal(node.left);
            preOrderTraversal(node.right);
        }
    }

    // Post-order traversal (Left, Right, Root)
    public void postOrderTraversal(TreeNode node)
        if (node != null)
            postOrderTraversal(node.left);
            postOrderTraversal(node.right);
            System.out.print(node.data + " ");
        }
    }

    // Search for a value in the tree
    public boolean search(int value)
        return searchHelper(root, value);
    }

    private boolean searchHelper(TreeNode node, int value)
        if (node == null)
            return false;
        }
        if (node.data == value)
            return true;
        }
        if (value < node.data)
            return searchHelper(node.left, value);
        } else
            return searchHelper(node.right, value);
        }
    }

    // Find minimum value in the tree
    public int findMin()
        if (root == null) return -1;
        TreeNode current = root;
        while (current.left != null)
            current = current.left;
        }
        return current.data;
    }

    // Find maximum value in the tree
    public int findMax()
        if (root == null) return -1;
        TreeNode current = root;
        while (current.right != null)
            current = current.right;
        }
        return current.data;
    }

    // Get the height of the tree
    public int getHeight()
        return getHeightHelper(root);
    }

    private int getHeightHelper(TreeNode node)
        if (node == null)
            return 0;
        }
        int leftHeight = getHeightHelper(node.left);
        int rightHeight = getHeightHelper(node.right);
        return Math.max(leftHeight, rightHeight) + 1;
    }

    // Delete a node from the tree
    public void delete(int value)
        root = deleteHelper(root, value);
    }

    private TreeNode deleteHelper(TreeNode node, int value)
        if (node == null) return null;

        if (value < node.data)
            node.left = deleteHelper(node.left, value);
        } else if (value > node.data)
            node.right = deleteHelper(node.right, value);
        } else
            // Node with only one child or no child
            if (node.left == null) return node.right;
            if (node.right == null) return node.left;

            // Node with two children: get inorder successor
            node.data = findMinValue(node.right);
            node.right = deleteHelper(node.right, node.data);
        }

        return node;
    }

    private int findMinValue(TreeNode node)
        while (node.left != null)
            node = node.left;
        }
        return node.data;
    }
}
